from flask import Flask, send_file, jsonify, g
import os
from io import BytesIO

app = Flask(__name__)

INVOICE_STORAGE_PATH = '/path/to/invoices'

def get_invoice_path(invoice_id):
    return os.path.join(INVOICE_STORAGE_PATH, f'invoice_{invoice_id}.pdf')

def check_invoice_ownership(invoice_id, user_id):
    invoice_owners = {
        1: 'user1',
        2: 'user1',
        3: 'user2',
        4: 'user3',
    }
    return invoice_owners.get(invoice_id) == user_id

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    user_id = g.user_id
    
    if not check_invoice_ownership(invoice_id, user_id):
        return jsonify({'error': 'Unauthorized access to invoice'}), 403
    
    invoice_path = get_invoice_path(invoice_id)
    
    if not os.path.exists(invoice_path):
        return jsonify({'error': 'Invoice not found'}), 404
    
    try:
        return send_file(
            invoice_path,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f'invoice_{invoice_id}.pdf'
        )
    except Exception as e:
        return jsonify({'error': 'Failed to download invoice'}), 500

